sal_id) VALUES ('c190033b-89b3-4d2a-aff1-131ea4d260e6', 'a18f39cf-60f6-4f05-a680-05c592350b7a', 'CENA EMPLEADOS', NULL, '#ff906d', true, '2026-05-22T03:53:24.628Z', '2026-05-22T03:53:24.628Z', 'bbd7297a-8f29-4b43-b813-3920fc7be932');\nINSERT INTO gasto_categorias (id, tenant_id, nombre, descripcion, color, activa, created_at, updated_at, sucursal_id) VALUES ('36a1f270-ae17-40e4-a425-15092ae0de12', 'a18f39cf-60f6-4f05-a680-05c592350b7a', 'NOMINA', NULL, '#ff906d', true, '2026-05-26T00:33:34.961Z', '2026-05-26T00:33:34.961Z', NULL);\nINSERT INTO gasto_categorias (id, tenant_id, nombre, descripcion, color, activa, created_at, updated_at, sucursal_id) VALUES ('05602181-368f-4f46-969c-38ce6dfb4fef', 'a18f39cf-60f6-4f05-a680-05c592350b7a', 'Nómina', 'Pagos al personal, adelantos y bonos.', '#f97316', true, '2026-05-27T00:39:01.519Z', '2026-05-27T00:39:01.519Z', NULL);\nINSERT INTO gasto_categorias (id, tenant_id, nombre, descripcion, color, activa, created_at, updated_at, sucursal_id) VALUES ('7d7e13ff-0797-42a7-9ead-9d40ef8364ec', '2a547d0e-4a0b-49e5-a7be-34071934c61d', 'Compra de Insumos', NULL, '#ff906d', true, '2026-06-08T18:39:43.838Z', '2026-06-08T18:39:43.838Z', '2933e7b6-21df-4bbc-8fc7-fa6e39da4df5');\nINSERT INTO gasto_categorias (id, tenant_id, nombre, descripcion, color, activa, created_at, updated_at, sucursal_id) VALUES ('35b169d0-d76a-438b-8626-6845a2848f47', '2a547d0e-4a0b-49e5-a7be-34071934c61d', 'Pago a Proveedores', NULL, '#25d366', true, '2026-06-08T18:39:57.681Z', '2026-06-08T18:39:57.681Z', '2933e7b6-21df-4bbc-8fc7-fa6e39da4df5');\nINSERT INTO gasto_categorias (id, tenant_id, nombre, descripcion, color, activa, created_at, updated_at, sucursal_id) VALUES ('965b1989-1122-4c17-b770-286da2688201', 'a18f39cf-60f6-4f05-a680-05c592350b7a', 'Compras', 'Categoría automática para registrar compras de insumos', '#ff906d', true, '2026-07-09T22:22:27.422Z', '2026-07-09T22:22:27.422Z', NULL);\n\n-- Table: gastos\nCREATE TABLE IF NOT EXISTS gastos (id uuid NOT NULL DEFAULT gen_random_uuid(), tenant_id uuid NOT NULL, category_id uuid, cycle_id uuid, descripcion text NOT NULL, proveedor text, monto numeric NOT NULL, metodo_pago text, fecha_gasto timestamptz NOT NULL DEFAULT now(), notas text, created_by_auth_user_id uuid, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), sucursal_id uuid);\n\n-- Indexes for table: gastos\nCREATE INDEX gastos_tenant_category_idx ON public.gastos USING btree (tenant_id, category_id);\nCREATE INDEX gastos_tenant_cycle_idx ON public.gastos USING btree (tenant_id, cycle_id);\nCREATE INDEX gastos_tenant_fecha_idx ON public.gastos USING btree (tenant_id, fecha_gasto DESC);\nCREATE INDEX idx_gastos_category_id ON public.gastos USING btree (category_id);\nCREATE INDEX idx_gastos_cycle_id ON public.gastos USING btree (cycle_id);\nCREATE INDEX idx_gastos_sucursal_id ON public.gastos USING btree (sucursal_id);\n\n-- Foreign key constraints for table: gastos\nALTER TABLE gastos ADD CONSTRAINT gastos_category_id_fkey FOREIGN KEY (category_id) REFERENCES gasto_categorias (id) ON DELETE SET NULL;\nALTER TABLE gastos ADD CONSTRAINT gastos_cycle_id_fkey FOREIGN KEY (cycle_id) REFERENCES cierres_operativos (id) ON DELETE SET NULL;\nALTER TABLE gastos ADD CONSTRAINT gastos_sucursal_id_fkey FOREIGN KEY (sucursal_id) REFERENCES sucursales (id) ON DELETE SET NULL;\nALTER TABLE gastos ADD CONSTRAINT gastos_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES tenants (id) ON DELETE CASCADE;\n\n-- RLS enabled for table: gastos\nALTER TABLE gastos ENABLE ROW LEVEL SECURITY;\n\n-- RLS policies for table: gastos\nCREATE POLICY cb_gastos_delete ON gastos FOR DELETE TO public USING ((EXISTS ( SELECT 1\n   FROM tenant_users tu\n  WHERE ((tu.tenant_id = gastos.tenant_id) AND (tu.activo IS TRUE) AND (tu.rol = 'admin'::text) AND ((tu.auth_user_id = cloudix_auth_user_id()) OR ((tu.auth_user_id IS NULL) AND (lower(tu.email) = lower(cloudix_auth_email()))))))));\nCREATE POLICY cb_gastos_insert ON gastos FOR INSERT TO public WITH CHECK ((EXISTS ( SELECT 1\n   FROM tenant_users tu\n  WHERE ((tu.tenant_id = gastos.tenant_id) AND (tu.activo IS TRUE) AND ((tu.auth_user_id = cloudix_auth_user_id()) OR ((tu.auth_user_id IS NULL) AND (lower(tu.email) = lower(cloudix_auth_email()))))))));\nCREATE POLICY cb_gastos_select ON gastos FOR SELECT TO public USING ((EXISTS ( SELECT 1\n   FROM tenant_users tu\n  WHERE ((tu.tenant_id = gastos.tenant_id) AND (tu.activo IS TRUE) AND ((tu.auth_user_id = cloudix_auth_user_id()) OR ((tu.auth_user_id IS NULL) AND (lower(tu.email) = lower(cloudix_auth_email()))))))));\nCREATE POLICY cb_gastos_update ON gastos FOR UPDATE TO public USING ((EXISTS ( SELECT 1\n   FROM tenant_users tu\n  WHERE ((tu.tenant_id = gastos.tenant_id) AND (tu.activo IS TRUE) AND ((tu.auth_user_id = cloudix_auth_user_id()) OR ((tu.auth_user_id IS NULL) AND (lower(tu.email) = lower(cloudix_auth_email())))))))) WITH CHECK ((EXISTS ( SELECT 1\n   FROM tenant_users tu\n  WHERE ((tu.tenant_id = gastos.tenant_id) AND (tu.activo IS TRUE) AND ((tu.auth_user_id = cloudix_auth_user_id()) OR ((tu.auth_user_id IS NULL) AND (lower(tu.email) = lower(cloudix_auth_email()))))))));\n\n-- Data for table: gastos\nINSERT INTO gastos (id, tenant_id, category_id, cycle_id, descripcion, proveedor, monto, metodo_pago, fecha_gasto, notas, created_by_auth_user_id, created_at, updated_at, sucursal_id) VALUES ('6cc7b007-c946-4d2f-ba64-449f76911541', 'a18f39cf-60f6-4f05-a680-05c592350b7a', 'f9a94f17-a2cb-450b-9909-2cfe5db49e2c', '4ca39ba3-ac0e-4115-b76c-6c3efdb79a39', 'productos', 'supermarket grullon', '5376.00', 'efectivo', '2026-05-27T00:02:00.000Z', NULL, 'ba047501-04b2-453a-8bd2-f39dd41c729f', '2026-05-27T00:00:12.381Z', '2026-05-27T00:00:12.381Z', NULL);\nINSERT INTO gastos (id, tenant_id, category_id, cycle_id, descripcion, proveedor, monto, metodo_pago, fecha_gasto, notas, created_by_auth_user_id, created_at, updated_at, sucursal_id) VALUES ('686ab538-631b-4068-b8ba-cfcfbe46727